<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>2048</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; }
  body {
    background: radial-gradient(ellipse at top, #1f1f3d 0%, #0a0a18 75%);
    color: #e8e8f0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Tahoma, sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 20px;
    user-select: none;
  }
  h1 {
    font-size: 72px;
    margin-bottom: 16px;
    background: linear-gradient(135deg, #ff8c42, #ffd166 50%, #ef476f);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    font-weight: 900;
    letter-spacing: -3px;
    line-height: 1;
  }
  .info {
    display: flex;
    gap: 16px;
    margin-bottom: 24px;
    align-items: stretch;
  }
  .score-box {
    background: rgba(26, 26, 46, 0.7);
    padding: 8px 28px;
    border-radius: 10px;
    text-align: center;
    border: 1px solid rgba(255, 255, 255, 0.06);
    min-width: 130px;
    display: flex;
    flex-direction: column;
    justify-content: center;
  }
  .score-box .label {
    font-size: 11px;
    color: #8888a8;
    text-transform: uppercase;
    letter-spacing: 2px;
    margin-bottom: 2px;
    font-weight: 600;
  }
  .score-box #score {
    font-size: 30px;
    font-weight: 800;
    color: #ffd166;
    line-height: 1.1;
  }
  #reset {
    background: linear-gradient(135deg, #ef476f, #ff6b35);
    color: white;
    border: none;
    padding: 0 24px;
    border-radius: 10px;
    font-size: 14px;
    font-weight: 700;
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.2s;
    box-shadow: 0 4px 14px rgba(239, 71, 111, 0.35);
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-family: inherit;
  }
  #reset:hover {
    box-shadow: 0 6px 20px rgba(239, 71, 111, 0.5);
    transform: translateY(-1px);
  }
  #reset:active { transform: translateY(0) scale(0.97); }

  #board {
    background: rgba(20, 20, 40, 0.6);
    padding: 12px;
    border-radius: 14px;
    display: grid;
    grid-template-columns: repeat(4, 88px);
    grid-template-rows: repeat(4, 88px);
    gap: 10px;
    border: 1px solid rgba(255, 255, 255, 0.05);
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.35);
  }
  .cell {
    background: rgba(15, 16, 32, 0.65);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 36px;
    font-weight: 800;
    color: #3d3d5a;
  }
  .tile-2    { background: #2d3047; color: #e8e8f0; }
  .tile-4    { background: #404466; color: #f0f0fa; }
  .tile-8    { background: linear-gradient(135deg, #ff8c42, #ff7a2e); color: white; }
  .tile-16   { background: linear-gradient(135deg, #ff6b35, #f05824); color: white; }
  .tile-32   { background: linear-gradient(135deg, #ef476f, #d63a5e); color: white; }
  .tile-64   { background: linear-gradient(135deg, #d63a5e, #b82e4d); color: white; }
  .tile-128  { background: linear-gradient(135deg, #ffd166, #f9c846); color: #1a1a2e; font-size: 30px; }
  .tile-256  { background: linear-gradient(135deg, #f9c846, #f0b429); color: #1a1a2e; font-size: 30px; }
  .tile-512  { background: linear-gradient(135deg, #f0b429, #e2a829); color: #1a1a2e; font-size: 30px; }
  .tile-1024 { background: linear-gradient(135deg, #e2a829, #c8901f); color: white; font-size: 24px; }
  .tile-2048 {
    background: linear-gradient(135deg, #ffd166, #ef476f);
    color: white;
    font-size: 24px;
    box-shadow: 0 0 24px rgba(255, 209, 102, 0.6);
  }
  .tile-super {
    background: linear-gradient(135deg, #ff6b35, #ef476f, #b82e4d);
    color: white;
    font-size: 22px;
    box-shadow: 0 0 24px rgba(239, 71, 111, 0.6);
  }

  .instructions {
    margin-top: 24px;
    color: #6a6a85;
    font-size: 13px;
    text-align: center;
    letter-spacing: 0.5px;
  }
  kbd {
    background: rgba(255,255,255,0.05);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 4px;
    padding: 2px 8px;
    font-family: monospace;
    font-size: 11px;
    color: #aaaac0;
    margin: 0 2px;
  }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="info">
    <div class="score-box">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div class="instructions">
    Use <kbd>&larr;</kbd> <kbd>&uarr;</kbd> <kbd>&darr;</kbd> <kbd>&rarr;</kbd> arrow keys to slide tiles. Merge to reach 2048!
  </div>

<script>
(function() {
  const SIZE = 4;
  let board = [];
  let score = 0;

  function emptyBoard() {
    return Array.from({length: SIZE}, () => new Array(SIZE).fill(0));
  }

  function cloneBoard(b) {
    return b.map(r => r.slice());
  }

  function transpose(b) {
    const n = b.length;
    const r = emptyBoard();
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) {
        r[j][i] = b[i][j];
      }
    }
    return r;
  }

  function reverseRows(b) {
    return b.map(row => row.slice().reverse());
  }

  // Slide every row left, merging equal adjacent pairs (each tile merges at most once).
  function slideLeft(b) {
    let gained = 0;
    const result = b.map(row => {
      const filtered = row.filter(x => x !== 0);
      const newRow = [];
      let i = 0;
      while (i < filtered.length) {
        if (i + 1 < filtered.length && filtered[i] === filtered[i + 1]) {
          newRow.push(filtered[i] * 2);
          gained += filtered[i] * 2;
          i += 2;
        } else {
          newRow.push(filtered[i]);
          i += 1;
        }
      }
      while (newRow.length < SIZE) newRow.push(0);
      return newRow;
    });
    return {board: result, gained: gained};
  }

  function boardsEqual(a, b) {
    for (let i = 0; i < SIZE; i++) {
      for (let j = 0; j < SIZE; j++) {
        if (a[i][j] !== b[i][j]) return false;
      }
    }
    return true;
  }

  function findEmpty(b) {
    const cells = [];
    for (let i = 0; i < SIZE; i++) {
      for (let j = 0; j < SIZE; j++) {
        if (b[i][j] === 0) cells.push([i, j]);
      }
    }
    return cells;
  }

  function spawnTile(b) {
    const empties = findEmpty(b);
    if (empties.length === 0) return false;
    const idx = Math.floor(Math.random() * empties.length);
    const [i, j] = empties[idx];
    b[i][j] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let i = 0; i < SIZE; i++) {
      for (let j = 0; j < SIZE; j++) {
        const v = board[i][j];
        const cell = document.createElement('div');
        cell.className = 'cell';
        if (v !== 0) {
          cell.classList.add('tile-' + (v <= 2048 ? v : 'super'));
          cell.textContent = v;
        }
        boardEl.appendChild(cell);
      }
    }
    document.getElementById('score').textContent = score;
  }

  function reset() {
    board = emptyBoard();
    score = 0;
    spawnTile(board);
    spawnTile(board);
    render();
  }

  function move(direction) {
    const before = cloneBoard(board);
    let result = null;

    switch (direction) {
      case 'left':
        result = slideLeft(board);
        board = result.board;
        break;
      case 'right':
        board = reverseRows(board);
        result = slideLeft(board);
        board = reverseRows(result.board);
        break;
      case 'up':
        board = transpose(board);
        result = slideLeft(board);
        board = transpose(result.board);
        break;
      case 'down':
        board = reverseRows(transpose(board));
        result = slideLeft(board);
        board = transpose(reverseRows(result.board));
        break;
      default:
        return false;
    }

    if (boardsEqual(before, board)) {
      return false;
    }

    score += result.gained;
    spawnTile(board);
    render();
    return true;
  }

  function setBoard(arr) {
    board = [];
    for (let i = 0; i < SIZE; i++) {
      const row = [];
      for (let j = 0; j < SIZE; j++) {
        const v = arr && arr[i] ? arr[i][j] : 0;
        row.push(Number(v) || 0);
      }
      board.push(row);
    }
    render();
  }

  function getBoard() {
    return cloneBoard(board);
  }

  function getScore() {
    return score;
  }

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: getBoard,
    setBoard: setBoard,
    score: getScore
  };

  document.getElementById('reset').addEventListener('click', function() {
    reset();
  });

  document.addEventListener('keydown', function(e) {
    const map = {
      'ArrowLeft': 'left',
      'ArrowRight': 'right',
      'ArrowUp': 'up',
      'ArrowDown': 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      window.game.move(map[e.key]);
    }
  });

  reset();
})();
</script>
</body>
</html>
